package br.com.ifba.ecologic_back_end.modulos.usuario.entity;

import br.com.ifba.ecologic_back_end.infraestrutura.persistence.PersistenceEntity;
import jakarta.persistence.*;
import lombok.*;

@Entity
@Table(name = "tb_usuario")
@Inheritance(strategy = InheritanceType.JOINED)
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
public abstract class Usuario extends PersistenceEntity {

    @Column(nullable = false, unique = true)
    private String email;

    @Column(nullable = false)
    private String senha;
}

package br.com.ifba.ecologic_back_end.modulos.usuario.entity;

import br.com.ifba.ecologic_back_end.infraestrutura.persistence.PersistenceEntity;
import jakarta.persistence.*;
import lombok.*;

@Entity
@Table(name = "tb_usuario")
@Inheritance(strategy = InheritanceType.JOINED)
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
public abstract class Usuario extends PersistenceEntity {

    @Column(nullable = false, unique = true)
    private String email;

    @Column(nullable = false)
    private String nome;

    @Column(nullable = false)
    private String senha;
}

package br.com.ifba.ecologic_back_end.modulos.usuario.controller;

import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioAdministradorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioDiretorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioAdministradorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioDiretorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.service.UsuarioIService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

/**
 * Controller REST para o módulo Usuário.
 */
@RestController
@RequestMapping("/api/v1/usuarios")
@RequiredArgsConstructor
public class UsuarioController {

    private final UsuarioIService usuarioIService;

    /**
     * Cria um novo usuário administrador.
     * POST /api/v1/usuarios/administradores
     */
    @PostMapping("/administradores")
    public ResponseEntity<UsuarioAdministradorResponseDTO> criarAdministrador(
            @RequestBody @Valid UsuarioAdministradorRequestDTO dto) {
        UsuarioAdministradorResponseDTO response = usuarioIService.criarAdministrador(dto);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    /**
     * Cria um novo usuário diretor.
     * POST /api/v1/usuarios/diretores
     */
    @PostMapping("/diretores")
    public ResponseEntity<UsuarioDiretorResponseDTO> criarDiretor(
            @RequestBody @Valid UsuarioDiretorRequestDTO dto) {
        UsuarioDiretorResponseDTO response = usuarioIService.criarDiretor(dto);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }
}

package br.com.ifba.ecologic_back_end.modulos.usuario.controller;

import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioAdministradorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioAdministradorUpdateRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioDiretorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioDiretorUpdateRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioAdministradorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioDiretorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.service.UsuarioIService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.List;
import java.util.UUID;

/**
 * Controller REST para o módulo Usuário.
 * Gerencia todas as operações CRUD (Create, Read, Update, Delete) de usuários.
 */
@RestController
@RequestMapping("/api/v1/usuarios")
@RequiredArgsConstructor
public class UsuarioController {

    private final UsuarioIService usuarioIService;

    // ========================
    // CRIAR (CREATE)
    // ========================

    /**
     * Cria um novo usuário administrador.
     * POST /api/v1/usuarios/administradores
     */
    @PostMapping("/administradores")
    public ResponseEntity<UsuarioAdministradorResponseDTO> criarAdministrador(
            @RequestBody @Valid UsuarioAdministradorRequestDTO dto) {
        UsuarioAdministradorResponseDTO response = usuarioIService.criarAdministrador(dto);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    /**
     * Cria um novo usuário diretor.
     * POST /api/v1/usuarios/diretores
     */
    @PostMapping("/diretores")
    public ResponseEntity<UsuarioDiretorResponseDTO> criarDiretor(
            @RequestBody @Valid UsuarioDiretorRequestDTO dto) {
        UsuarioDiretorResponseDTO response = usuarioIService.criarDiretor(dto);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    // ========================
    // OBTER (READ)
    // ========================

    /**
     * Obtém um usuário administrador pelo ID.
     * GET /api/v1/usuarios/administradores/{id}
     */
    @GetMapping("/administradores/{id}")
    public ResponseEntity<UsuarioAdministradorResponseDTO> obterAdministrador(@PathVariable UUID id) {
        UsuarioAdministradorResponseDTO response = usuarioIService.obterAdministrador(id);
        return ResponseEntity.ok(response);
    }

    /**
     * Obtém um usuário diretor pelo ID.
     * GET /api/v1/usuarios/diretores/{id}
     */
    @GetMapping("/diretores/{id}")
    public ResponseEntity<UsuarioDiretorResponseDTO> obterDiretor(@PathVariable UUID id) {
        UsuarioDiretorResponseDTO response = usuarioIService.obterDiretor(id);
        return ResponseEntity.ok(response);
    }

    /**
     * Lista todos os usuários administradores.
     * GET /api/v1/usuarios/administradores
     */
    @GetMapping("/administradores")
    public ResponseEntity<List<UsuarioAdministradorResponseDTO>> listarAdministradores() {
        List<UsuarioAdministradorResponseDTO> response = usuarioIService.listarAdministradores();
        return ResponseEntity.ok(response);
    }

    /**
     * Lista todos os usuários diretores.
     * GET /api/v1/usuarios/diretores
     */
    @GetMapping("/diretores")
    public ResponseEntity<List<UsuarioDiretorResponseDTO>> listarDiretores() {
        List<UsuarioDiretorResponseDTO> response = usuarioIService.listarDiretores();
        return ResponseEntity.ok(response);
    }

    // ========================
    // ATUALIZAR (UPDATE)
    // ========================

    /**
     * Atualiza um usuário administrador.
     * PUT /api/v1/usuarios/administradores/{id}
     */
    @PutMapping("/administradores/{id}")
    public ResponseEntity<UsuarioAdministradorResponseDTO> atualizarAdministrador(
            @PathVariable UUID id,
            @RequestBody @Valid UsuarioAdministradorUpdateRequestDTO dto) {
        UsuarioAdministradorResponseDTO response = usuarioIService.atualizarAdministrador(id, dto);
        return ResponseEntity.ok(response);
    }

    /**
     * Atualiza um usuário diretor.
     * PUT /api/v1/usuarios/diretores/{id}
     */
    @PutMapping("/diretores/{id}")
    public ResponseEntity<UsuarioDiretorResponseDTO> atualizarDiretor(
            @PathVariable UUID id,
            @RequestBody @Valid UsuarioDiretorUpdateRequestDTO dto) {
        UsuarioDiretorResponseDTO response = usuarioIService.atualizarDiretor(id, dto);
        return ResponseEntity.ok(response);
    }

    // ========================
    // DELETAR (DELETE)
    // ========================

    /**
     * Deleta um usuário administrador.
     * DELETE /api/v1/usuarios/administradores/{id}
     */
    @DeleteMapping("/administradores/{id}")
    public ResponseEntity<Void> deletarAdministrador(@PathVariable UUID id) {
        usuarioIService.deletarAdministrador(id);
        return ResponseEntity.noContent().build();
    }

    /**
     * Deleta um usuário diretor.
     * DELETE /api/v1/usuarios/diretores/{id}
     */
    @DeleteMapping("/diretores/{id}")
    public ResponseEntity<Void> deletarDiretor(@PathVariable UUID id) {
        usuarioIService.deletarDiretor(id);
        return ResponseEntity.noContent().build();
    }
}

package br.com.ifba.ecologic_back_end.modulos.usuario.service;

import br.com.ifba.ecologic_back_end.exception.BusinessException;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioAdministradorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioDiretorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioAdministradorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioDiretorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.entity.UsuarioAdministrador;
import br.com.ifba.ecologic_back_end.modulos.usuario.entity.UsuarioDiretor;
import br.com.ifba.ecologic_back_end.modulos.usuario.mapper.UsuarioMapper;
import br.com.ifba.ecologic_back_end.modulos.usuario.repository.UsuarioAdministradorRepository;
import br.com.ifba.ecologic_back_end.modulos.usuario.repository.UsuarioDiretorRepository;
import br.com.ifba.ecologic_back_end.modulos.usuario.repository.UsuarioRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

/**
 * Implementação do serviço de Usuário.
 */
@Service
@RequiredArgsConstructor
public class UsuarioService implements UsuarioIService {

    private final UsuarioRepository usuarioRepository;
    private final UsuarioAdministradorRepository administradorRepository;
    private final UsuarioDiretorRepository diretorRepository;
    private final UsuarioMapper usuarioMapper;
    private final PasswordEncoder passwordEncoder;

    @Override
    public UsuarioAdministradorResponseDTO criarAdministrador(UsuarioAdministradorRequestDTO dto) {
        // Verifica se o email já está cadastrado
        validarEmailDuplicado(dto.getEmail());

        // Converte DTO para entidade
        UsuarioAdministrador admin = usuarioMapper.toEntity(dto);

        // Criptografa a senha antes de salvar
        admin.setSenha(passwordEncoder.encode(admin.getSenha()));

        UsuarioAdministrador adminSalvo = administradorRepository.save(admin);

        return usuarioMapper.toResponseDTO(adminSalvo);
    }

    @Override
    public UsuarioDiretorResponseDTO criarDiretor(UsuarioDiretorRequestDTO dto) {
        // Verifica se o email já está cadastrado
        validarEmailDuplicado(dto.getEmail());

        // Converte DTO para entidade
        UsuarioDiretor diretor = usuarioMapper.toEntity(dto);

        // Criptografa a senha antes de salvar
        diretor.setSenha(passwordEncoder.encode(diretor.getSenha()));

        UsuarioDiretor diretorSalvo = diretorRepository.save(diretor);

        return usuarioMapper.toResponseDTO(diretorSalvo);
    }

    /**
     * Valida se já existe um usuário com o email informado.
     * Lança BusinessException caso o email já esteja em uso.
     */
    private void validarEmailDuplicado(String email) {
        if (usuarioRepository.existsByEmail(email)) {
            throw new BusinessException("Já existe um usuário cadastrado com o email: " + email);
        }
    }
}

package br.com.ifba.ecologic_back_end.modulos.usuario.service;

import br.com.ifba.ecologic_back_end.exception.BusinessException;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioAdministradorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioAdministradorUpdateRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioDiretorRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.request.UsuarioDiretorUpdateRequestDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioAdministradorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.dto.response.UsuarioDiretorResponseDTO;
import br.com.ifba.ecologic_back_end.modulos.usuario.entity.UsuarioAdministrador;
import br.com.ifba.ecologic_back_end.modulos.usuario.entity.UsuarioDiretor;
import br.com.ifba.ecologic_back_end.modulos.usuario.mapper.UsuarioMapper;
import br.com.ifba.ecologic_back_end.modulos.usuario.repository.UsuarioAdministradorRepository;
import br.com.ifba.ecologic_back_end.modulos.usuario.repository.UsuarioDiretorRepository;
import br.com.ifba.ecologic_back_end.modulos.usuario.repository.UsuarioRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

/**
 * Implementação do serviço de Usuário.
 */
@Service
@RequiredArgsConstructor
public class UsuarioService implements UsuarioIService {

    private final UsuarioRepository usuarioRepository;
    private final UsuarioAdministradorRepository administradorRepository;
    private final UsuarioDiretorRepository diretorRepository;
    private final UsuarioMapper usuarioMapper;
    private final PasswordEncoder passwordEncoder;

    @Override
    public UsuarioAdministradorResponseDTO criarAdministrador(UsuarioAdministradorRequestDTO dto) {
        // Verifica se o email já está cadastrado
        validarEmailDuplicado(dto.getEmail());

        // Converte DTO para entidade
        UsuarioAdministrador admin = usuarioMapper.toEntity(dto);

        // Criptografa a senha antes de salvar
        admin.setSenha(passwordEncoder.encode(admin.getSenha()));

        UsuarioAdministrador adminSalvo = administradorRepository.save(admin);

        return usuarioMapper.toResponseDTO(adminSalvo);
    }

    @Override
    public UsuarioDiretorResponseDTO criarDiretor(UsuarioDiretorRequestDTO dto) {
        // Verifica se o email já está cadastrado
        validarEmailDuplicado(dto.getEmail());

        // Converte DTO para entidade
        UsuarioDiretor diretor = usuarioMapper.toEntity(dto);

        // Criptografa a senha antes de salvar
        diretor.setSenha(passwordEncoder.encode(diretor.getSenha()));

        UsuarioDiretor diretorSalvo = diretorRepository.save(diretor);

        return usuarioMapper.toResponseDTO(diretorSalvo);
    }

    @Override
    public UsuarioAdministradorResponseDTO obterAdministrador(UUID id) {
        UsuarioAdministrador admin = administradorRepository.findById(id)
                .orElseThrow(() -> new BusinessException("Usuário administrador não encontrado com ID: " + id));
        return usuarioMapper.toResponseDTO(admin);
    }

    @Override
    public UsuarioDiretorResponseDTO obterDiretor(UUID id) {
        UsuarioDiretor diretor = diretorRepository.findById(id)
                .orElseThrow(() -> new BusinessException("Usuário diretor não encontrado com ID: " + id));
        return usuarioMapper.toResponseDTO(diretor);
    }

    @Override
    public List<UsuarioAdministradorResponseDTO> listarAdministradores() {
        return administradorRepository.findAll()
                .stream()
                .map(usuarioMapper::toResponseDTO)
                .collect(Collectors.toList());
    }

    @Override
    public List<UsuarioDiretorResponseDTO> listarDiretores() {
        return diretorRepository.findAll()
                .stream()
                .map(usuarioMapper::toResponseDTO)
                .collect(Collectors.toList());
    }

    @Override
    public UsuarioAdministradorResponseDTO atualizarAdministrador(UUID id, UsuarioAdministradorUpdateRequestDTO dto) {
        UsuarioAdministrador admin = administradorRepository.findById(id)
                .orElseThrow(() -> new BusinessException("Usuário administrador não encontrado com ID: " + id));

        // Atualiza o cargo
        admin.setCargo(dto.getCargo());

        UsuarioAdministrador adminAtualizado = administradorRepository.save(admin);

        return usuarioMapper.toResponseDTO(adminAtualizado);
    }

    @Override
    public UsuarioDiretorResponseDTO atualizarDiretor(UUID id, UsuarioDiretorUpdateRequestDTO dto) {
        UsuarioDiretor diretor = diretorRepository.findById(id)
                .orElseThrow(() -> new BusinessException("Usuário diretor não encontrado com ID: " + id));

        // Atualiza a titulação
        diretor.setTitulacao(dto.getTitulacao());

        UsuarioDiretor diretorAtualizado = diretorRepository.save(diretor);

        return usuarioMapper.toResponseDTO(diretorAtualizado);
    }

    @Override
    public void deletarAdministrador(UUID id) {
        if (!administradorRepository.existsById(id)) {
            throw new BusinessException("Usuário administrador não encontrado com ID: " + id);
        }
        administradorRepository.deleteById(id);
    }

    @Override
    public void deletarDiretor(UUID id) {
        if (!diretorRepository.existsById(id)) {
            throw new BusinessException("Usuário diretor não encontrado com ID: " + id);
        }
        diretorRepository.deleteById(id);
    }

    /**
     * Valida se já existe um usuário com o email informado.
     * Lança BusinessException caso o email já esteja em uso.
     */
    private void validarEmailDuplicado(String email) {
        if (usuarioRepository.existsByEmail(email)) {
            throw new BusinessException("Já existe um usuário cadastrado com o email: " + email);
        }
    }
}
